 1→export type SessionId = string;
 2→export type MessageId = string;
 3→export type ReminderId = string;
 4→
 5→export type MessageRole = "user" | "assistant" | "system";
 6→export type SessionStatus = "active" | "archived";
 7→
 8→export interface Session {
 9→  id: SessionId;
10→  name: string;
11→  workingDirectory: string;
12→  claudeSessionId: string | null;
13→  createdAt: number;
14→  lastActiveAt: number;
15→  status: SessionStatus;
16→}
17→
18→export interface Message {
19→  id: MessageId;
20→  sessionId: SessionId;
21→  role: MessageRole;
22→  content: string;
23→  createdAt: number;
24→  metadata: string | null;
25→}
26→
27→export interface Reminder {
28→  id: ReminderId;
29→  sessionId: SessionId | null;
30→  content: string;
31→  persistent: boolean;
32→  active: boolean;
33→  priority: number;
34→  triggerCondition: string | null;
35→  createdAt: number;
36→}
37→
38→export interface MessageMetadata {
39→  toolCalls?: string[];
40→  injectedReminders?: string[];
41→  claudeSessionId?: string;
42→  cost?: number;
43→  duration?: number;
44→}
45→
46→export interface ChatState {
