  1→import {
  2→  handleWebSocketOpen,
  3→  handleWebSocketClose,
  4→  handleWebSocketMessage,
  5→  getConnectedClients,
  6→} from "./websocket";
  7→import { db } from "./db";
  8→
  9→const PORT = Number(Bun.env.TERMINAL_PORT) || 3001;
 10→
 11→interface WebSocketData {
 12→  id: string;
 13→  connectedAt: number;
 14→}
 15→
 16→const corsHeaders = {
 17→  "Access-Control-Allow-Origin": "*",
 18→  "Access-Control-Allow-Methods": "GET, POST, PUT, PATCH, DELETE, OPTIONS",
 19→  "Access-Control-Allow-Headers": "Content-Type",
 20→};
 21→
 22→function jsonResponse(data: unknown, status = 200) {
 23→  return new Response(JSON.stringify(data), {
 24→    status,
 25→    headers: { "Content-Type": "application/json", ...corsHeaders },
 26→  });
 27→}
 28→
 29→async function parseBody<T>(req: Request): Promise<T> {
 30→  return (await req.json()) as T;
 31→}
 32→
 33→const server = Bun.serve<WebSocketData>({
 34→  port: PORT,
 35→
 36→  async fetch(req, server) {
 37→    const url = new URL(req.url);
 38→
 39→    // CORS preflight
 40→    if (req.method === "OPTIONS") {
 41→      return new Response(null, { headers: corsHeaders });
 42→    }
 43→
 44→    // Health check
 45→    if (url.pathname === "/health") {
 46→      return jsonResponse({
 47→        status: "ok",
 48→        clients: getConnectedClients(),
 49→        uptime: process.uptime(),
 50→      });
 51→    }
 52→
 53→    // WebSocket upgrade
 54→    if (url.pathname === "/ws") {
 55→      const upgraded = server.upgrade(req, {
 56→        data: { id: "", connectedAt: 0 },
 57→      });
 58→      if (!upgraded) {
 59→        return new Response("WebSocket upgrade failed", { status: 400 });
 60→      }
 61→      return undefined;
 62→    }
 63→
 64→    // ============ SESSIONS API ============
 65→    if (url.pathname === "/api/sessions") {
 66→      if (req.method === "GET") {
 67→        const status = url.searchParams.get("status") as "active" | "archived" | null;
 68→        const sessions = db.listSessions(status ?? undefined);
 69→        return jsonResponse(sessions);
 70→      }
 71→
 72→      if (req.method === "POST") {
 73→        const body = await parseBody<{ name: string; workingDirectory: string }>(req);
 74→        const session = db.createSession(body.name, body.workingDirectory || "/");
 75→        return jsonResponse(session, 201);
 76→      }
 77→    }
 78→
 79→    const sessionMatch = url.pathname.match(/^\/api\/sessions\/([^/]+)$/);
 80→    if (sessionMatch) {
 81→      const sessionId = sessionMatch[1];
 82→
 83→      if (req.method === "GET") {
 84→        const session = db.getSession(sessionId);
 85→        if (!session) return jsonResponse({ error: "Session not found" }, 404);
 86→        return jsonResponse(session);
 87→      }
 88→
 89→      if (req.method === "PATCH") {
 90→        const body = await parseBody<{ claudeSessionId?: string; status?: "archived" }>(req);
 91→        if (body.claudeSessionId) {
 92→          db.updateSessionClaudeId(sessionId, body.claudeSessionId);
 93→        }
 94→        if (body.status === "archived") {
 95→          db.archiveSession(sessionId);
 96→        }
 97→        const session = db.getSession(sessionId);
 98→        return jsonResponse(session);
 99→      }
100→
101→      if (req.method === "DELETE") {
102→        db.deleteSession(sessionId);
103→        return jsonResponse({ success: true });
104→      }
105→    }
106→
107→    // ============ MESSAGES API ============
108→    const messagesMatch = url.pathname.match(/^\/api\/sessions\/([^/]+)\/messages$/);
109→    if (messagesMatch) {
110→      const sessionId = messagesMatch[1];
111→
112→      if (req.method === "GET") {
113→        const limit = url.searchParams.get("limit");
114→        const messages = db.getMessages(sessionId, limit ? parseInt(limit) : undefined);
115→        return jsonResponse(messages);
116→      }
117→
118→      if (req.method === "POST") {
119→        const body = await parseBody<{
120→          role: "user" | "assistant" | "system";
121→          content: string;
122→          metadata?: Record<string, unknown>;
123→        }>(req);
124→        const message = db.addMessage(sessionId, body.role, body.content, body.metadata as any);
125→        return jsonResponse(message, 201);
126→      }
127→    }
128→
129→    const messageMatch = url.pathname.match(/^\/api\/messages\/([^/]+)$/);
130→    if (messageMatch) {
131→      const messageId = messageMatch[1];
132→
133→      if (req.method === "GET") {
134→        const message = db.getMessage(messageId);
135→        if (!message) return jsonResponse({ error: "Message not found" }, 404);
136→        return jsonResponse(message);
137→      }
138→
139→      if (req.method === "PATCH") {
140→        const body = await parseBody<{ content?: string; metadata?: Record<string, unknown> }>(req);
141→        if (body.content !== undefined) {
142→          db.updateMessageContent(messageId, body.content);
143→        }
144→        if (body.metadata !== undefined) {
145→          db.updateMessageMetadata(messageId, body.metadata as any);
146→        }
147→        const message = db.getMessage(messageId);
148→        return jsonResponse(message);
149→      }
150→    }
151→
152→    // ============ REMINDERS API ============
153→    if (url.pathname === "/api/reminders") {
154→      if (req.method === "GET") {
155→        const sessionId = url.searchParams.get("sessionId") ?? undefined;
156→        const activeOnly = url.searchParams.get("active") === "true";
157→        const reminders = activeOnly
158→          ? db.getActiveReminders(sessionId)
159→          : db.getAllReminders(sessionId);
160→        return jsonResponse(reminders);
161→      }
162→
163→      if (req.method === "POST") {
164→        const body = await parseBody<{
165→          content: string;
166→          persistent: boolean;
167→          sessionId?: string;
168→          priority?: number;
169→          triggerCondition?: string;
170→        }>(req);
171→        const reminder = db.createReminder(
172→          body.content,
173→          body.persistent,
174→          body.sessionId,
175→          body.priority,
176→          body.triggerCondition,
177→        );
178→        return jsonResponse(reminder, 201);
179→      }
180→    }
181→
182→    const reminderMatch = url.pathname.match(/^\/api\/reminders\/([^/]+)$/);
183→    if (reminderMatch) {
184→      const reminderId = reminderMatch[1];
185→
186→      if (req.method === "PATCH") {
187→        const body = await parseBody<{
188→          content?: string;
189→          persistent?: boolean;
190→          active?: boolean;
191→          priority?: number;
192→          triggerCondition?: string;
193→        }>(req);
194→        db.updateReminder(reminderId, body);
195→        return jsonResponse({ success: true });
196→      }
197→
198→      if (req.method === "DELETE") {
199→        db.deleteReminder(reminderId);
200→        return jsonResponse({ success: true });
201→      }
202→    }
203→
204→    // ============ TEST API ============
205→    if (url.pathname === "/api/test/reset") {
206→      if (req.method === "POST") {
207→        db.reset();
208→        return jsonResponse({ success: true, message: "Database reset" });
209→      }
210→    }
211→
212→    return new Response("Not found", { status: 404, headers: corsHeaders });
213→  },
214→
215→  websocket: {
216→    open(ws) {
217→      handleWebSocketOpen(ws);
218→    },
219→    close(ws) {
220→      handleWebSocketClose(ws);
221→    },
222→    message(ws, message) {
223→      handleWebSocketMessage(ws, message);
224→    },
225→    drain(_ws) {
226→      // Handle backpressure
227→    },
228→  },
229→});
230→
231→console.log(`[Terminal Server] Running on http://localhost:${PORT}`);
232→console.log(`[Terminal Server] WebSocket: ws://localhost:${PORT}/ws`);
233→console.log(`[Terminal Server] API: http://localhost:${PORT}/api/*`);
234→
235→export { server };
