  1→import { Database } from "bun:sqlite";
  2→import { randomUUID } from "crypto";
  3→import { join } from "path";
  4→import { mkdirSync, existsSync } from "fs";
  5→
  6→const DB_PATH = join(import.meta.dir, "../../data/terminal.db");
  7→
  8→export interface Session {
  9→  id: string;
 10→  name: string;
 11→  workingDirectory: string;
 12→  claudeSessionId: string | null;
 13→  createdAt: number;
 14→  lastActiveAt: number;
 15→  status: "active" | "archived";
 16→}
 17→
 18→export interface Message {
 19→  id: string;
 20→  sessionId: string;
 21→  role: "user" | "assistant" | "system";
 22→  content: string;
 23→  createdAt: number;
 24→  metadata: string | null;
 25→}
 26→
 27→export interface Reminder {
 28→  id: string;
 29→  sessionId: string | null;
 30→  content: string;
 31→  persistent: boolean;
 32→  active: boolean;
 33→  priority: number;
 34→  triggerCondition: string | null;
 35→  createdAt: number;
 36→}
 37→
 38→export interface ParsedMetadata {
 39→  toolCalls?: string[];
 40→  injectedReminders?: string[];
 41→  claudeSessionId?: string;
 42→  cost?: number;
 43→  duration?: number;
 44→}
 45→
 46→class TerminalDatabase {
 47→  private db: Database;
 48→
 49→  constructor(dbPath: string = DB_PATH) {
 50→    const dir = dbPath.substring(0, dbPath.lastIndexOf("/"));
 51→    if (dir && !existsSync(dir)) {
 52→      mkdirSync(dir, { recursive: true });
 53→    }
 54→
 55→    this.db = new Database(dbPath);
 56→    this.db.exec("PRAGMA journal_mode = WAL");
 57→    this.init();
 58→  }
 59→
 60→  private init() {
 61→    this.db.exec(`
 62→      CREATE TABLE IF NOT EXISTS sessions (
 63→        id TEXT PRIMARY KEY,
 64→        name TEXT NOT NULL,
 65→        working_directory TEXT NOT NULL,
 66→        claude_session_id TEXT,
 67→        created_at INTEGER NOT NULL,
 68→        last_active_at INTEGER NOT NULL,
 69→        status TEXT DEFAULT 'active'
 70→      );
 71→
 72→      CREATE TABLE IF NOT EXISTS messages (
 73→        id TEXT PRIMARY KEY,
 74→        session_id TEXT NOT NULL,
 75→        role TEXT NOT NULL,
 76→        content TEXT NOT NULL,
 77→        created_at INTEGER NOT NULL,
 78→        metadata TEXT,
 79→        FOREIGN KEY (session_id) REFERENCES sessions(id) ON DELETE CASCADE
 80→      );
 81→
 82→      CREATE TABLE IF NOT EXISTS reminders (
 83→        id TEXT PRIMARY KEY,
 84→        session_id TEXT,
 85→        content TEXT NOT NULL,
 86→        persistent INTEGER NOT NULL,
 87→        active INTEGER DEFAULT 1,
 88→        priority INTEGER DEFAULT 0,
 89→        trigger_condition TEXT,
 90→        created_at INTEGER NOT NULL,
 91→        FOREIGN KEY (session_id) REFERENCES sessions(id) ON DELETE CASCADE
 92→      );
 93→
 94→      CREATE INDEX IF NOT EXISTS idx_messages_session ON messages(session_id);
 95→      CREATE INDEX IF NOT EXISTS idx_reminders_session ON reminders(session_id);
 96→      CREATE INDEX IF NOT EXISTS idx_reminders_active ON reminders(active);
 97→    `);
 98→  }
 99→
100→  // Sessions
101→  createSession(name: string, workingDirectory: string): Session {
102→    const id = randomUUID();
103→    const now = Date.now();
104→
105→    this.db
106→      .prepare(
107→        `INSERT INTO sessions (id, name, working_directory, created_at, last_active_at, status)
108→         VALUES (?, ?, ?, ?, ?, 'active')`,
109→      )
110→      .run(id, name, workingDirectory, now, now);
111→
112→    return {
113→      id,
114→      name,
