354→  reset(): void {
355→    this.db.exec(`
356→      DELETE FROM reminders;
357→      DELETE FROM messages;
358→      DELETE FROM sessions;
359→    `);
360→  }
361→
362→  close(): void {
363→    this.db.close();
364→  }
365→}
