 48→  type: "system";
 49→  subtype: string;
 50→  message?: string;
 51→  [key: string]: unknown;
 52→}
 53→
 54→export type ClaudeEvent = ClaudeAssistantMessage | ClaudeResultEvent | ClaudeSystemEvent | ClaudeStreamEvent;
 55→
 56→export interface ClaudeOptions {
 57→  prompt: string;
 58→  workingDirectory: string;
 59→  sessionId?: string;
 60→  systemPrompt?: string;
 61→  allowedTools?: string[];
 62→  maxTurns?: number;
 63→}
 64→
 65→export interface ClaudeController extends EventEmitter {
 66→  on(event: "data", listener: (data: ClaudeEvent) => void): this;
 67→  on(event: "text", listener: (text: string) => void): this;
 68→  on(event: "tool_use", listener: (tool: string, input: Record<string, unknown>) => void): this;
 69→  on(event: "result", listener: (result: ClaudeResultEvent) => void): this;
 70→  on(event: "error", listener: (error: Error) => void): this;
 71→  on(event: "end", listener: () => void): this;
 72→  emit(event: "data", data: ClaudeEvent): boolean;
 73→  emit(event: "text", text: string): boolean;
 74→  emit(event: "tool_use", tool: string, input: Record<string, unknown>): boolean;
 75→  emit(event: "result", result: ClaudeResultEvent): boolean;
 76→  emit(event: "error", error: Error): boolean;
 77→  emit(event: "end"): boolean;
 78→}
 79→
 80→export function createClaudeController(options: ClaudeOptions): ClaudeController {
 81→  const emitter = new EventEmitter() as ClaudeController;
 82→  let childProcess: ChildProcess | null = null;
 83→  let readline: Interface | null = null;
 84→
 85→  const args: string[] = ["-p", options.prompt, "--output-format", "stream-json"];
 86→
 87→  if (options.sessionId) {
 88→    args.push("--resume", options.sessionId);
 89→  }
 90→
 91→  if (options.systemPrompt) {
 92→    args.push("--append-system-prompt", options.systemPrompt);
 93→  }
 94→
 95→  if (options.allowedTools && options.allowedTools.length > 0) {
 96→    args.push("--allowedTools", options.allowedTools.join(","));
 97→  }
 98→
 99→  if (options.maxTurns) {
100→    args.push("--max-turns", String(options.maxTurns));
101→  }
102→
103→  setImmediate(() => {
104→    try {
105→      childProcess = spawn("claude", args, {
106→        cwd: options.workingDirectory,
107→        stdio: ["pipe", "pipe", "pipe"],
108→        env: { ...process.env, FORCE_COLOR: "0" },
109→      });
110→
111→      readline = createInterface({
112→        input: childProcess.stdout!,
113→        crlfDelay: Infinity,
114→      });
115→
116→      let accumulatedText = "";
117→
118→      readline.on("line", (line: string) => {
119→        if (!line.trim()) return;
120→
121→        try {
122→          const event = JSON.parse(line) as ClaudeEvent;
123→          emitter.emit("data", event);
124→
125→          if (event.type === "assistant") {
126→            const assistantEvent = event as ClaudeAssistantMessage;
127→            for (const block of assistantEvent.message.content) {
128→              if (block.type === "text" && block.text) {
129→                accumulatedText += block.text;
130→                emitter.emit("text", block.text);
131→              } else if (block.type === "tool_use" && block.name) {
132→                emitter.emit("tool_use", block.name, block.input ?? {});
133→              }
134→            }
135→          } else if (event.type === "result") {
136→            emitter.emit("result", event as ClaudeResultEvent);
137→          }
138→        } catch {
139→          // Ignore non-JSON lines (e.g., progress indicators)
140→        }
141→      });
142→
143→      childProcess.stderr?.on("data", (data: Buffer) => {
144→        const text = data.toString();
145→        if (text.includes("Error") || text.includes("error")) {
146→          emitter.emit("error", new Error(text));
147→        }
148→      });
149→
150→      childProcess.on("close", (code: number | null) => {
151→        readline?.close();
152→        if (code !== 0 && code !== null) {
153→          emitter.emit("error", new Error(`Claude process exited with code ${code}`));
154→        }
155→        emitter.emit("end");
156→      });
157→
158→      childProcess.on("error", (err: Error) => {
159→        emitter.emit("error", err);
160→        emitter.emit("end");
161→      });
162→    } catch (err) {
163→      emitter.emit("error", err instanceof Error ? err : new Error(String(err)));
164→      emitter.emit("end");
165→    }
166→  });
167→
168→  return emitter;
169→}
170→
171→export async function runClaude(options: ClaudeOptions): Promise<{
172→  text: string;
173→  sessionId: string | null;
174→  result: ClaudeResultEvent | null;
175→  toolCalls: Array<{ tool: string; input: Record<string, unknown> }>;
176→}> {
177→  return new Promise((resolve, reject) => {
178→    const controller = createClaudeController(options);
179→
180→    let text = "";
181→    let sessionId: string | null = null;
182→    let result: ClaudeResultEvent | null = null;
183→    const toolCalls: Array<{ tool: string; input: Record<string, unknown> }> = [];
184→
185→    controller.on("text", (chunk) => {
186→      text += chunk;
187→    });
188→
189→    controller.on("tool_use", (tool, input) => {
190→      toolCalls.push({ tool, input });
191→    });
192→
193→    controller.on("data", (event) => {
194→      if ("session_id" in event && event.session_id) {
195→        sessionId = event.session_id as string;
196→      }
197→    });
198→
199→    controller.on("result", (r) => {
200→      result = r;
201→      if (r.session_id) {
202→        sessionId = r.session_id;
203→      }
204→    });
205→
206→    controller.on("error", reject);
207→
208→    controller.on("end", () => {
209→      resolve({ text, sessionId, result, toolCalls });
210→    });
211→  });
212→}
