214→export function buildReminderSystemPrompt(reminders: Array<{ content: string; persistent: boolean }>): string {
215→  if (reminders.length === 0) return "";
216→
217→  const lines = reminders.map((r) => {
218→    const prefix = r.persistent ? "[PERSISTENT]" : "[ONE-TIME]";
219→    return `- ${prefix} ${r.content}`;
220→  });
221→
222→  return `ACTIVE REMINDERS (follow these instructions):
223→${lines.join("\n")}`;
224→}
