 51→export function shouldTriggerReminder(
 52→  reminder: Reminder,
 53→  userMessage: string,
 54→): boolean {
 55→  if (!reminder.triggerCondition) return true;
 56→
 57→  const condition = reminder.triggerCondition.trim();
 58→
 59→  const looksLikeKeywords = /^[\w,\s-]+$/.test(condition) && condition.includes(",");
 60→
 61→  if (looksLikeKeywords) {
 62→    return condition
 63→      .toLowerCase()
 64→      .split(",")
 65→      .some((keyword) =>
 66→        userMessage.toLowerCase().includes(keyword.trim()),
 67→      );
 68→  }
 69→
 70→  try {
 71→    const pattern = new RegExp(condition, "i");
 72→    return pattern.test(userMessage);
 73→  } catch {
 74→    return userMessage.toLowerCase().includes(condition.toLowerCase());
 75→  }
 76→}
 77→
 78→export function filterTriggeredReminders(
 79→  reminders: Reminder[],
 80→  userMessage: string,
 81→): Reminder[] {
 82→  return reminders.filter(
 83→    (r) => r.active && shouldTriggerReminder(r, userMessage),
 84→  );
 85→}
